import{_ as e,o as l,c as a,a6 as r}from"./chunks/framework.DxlbIVIm.js";const f=JSON.parse('{"title":"劇情對話總覽 (Story Dialogues Overview)","description":"","frontmatter":{},"headers":[],"relativePath":"story/dialogues.md","filePath":"story/dialogues.md"}'),d={name:"story/dialogues.md"};function n(s,t,o,g,i,y){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="劇情對話總覽-story-dialogues-overview" tabindex="-1">劇情對話總覽 (Story Dialogues Overview) <a class="header-anchor" href="#劇情對話總覽-story-dialogues-overview" aria-label="Permalink to &quot;劇情對話總覽 (Story Dialogues Overview)&quot;">​</a></h1><p>本文件集中管理《禁忌的Show》中所有劇情的對話內容，包含角色獨白、衝突對話及小遊戲觀戰台詞。</p><hr><h2 id="📅-day-0-序章-禁忌的開端" tabindex="-1">📅 Day 0 序章：禁忌的開端 <a class="header-anchor" href="#📅-day-0-序章-禁忌的開端" aria-label="Permalink to &quot;📅 Day 0 序章：禁忌的開端&quot;">​</a></h2><h3 id="_0-1-神祕邀請-玩家獨白" tabindex="-1">0.1 神祕邀請 (玩家獨白) <a class="header-anchor" href="#_0-1-神祕邀請-玩家獨白" aria-label="Permalink to &quot;0.1 神祕邀請 (玩家獨白)&quot;">​</a></h3><blockquote><p><strong>場景</strong>：深夜，只有螢幕微光的公寓。空氣中瀰漫著廉價咖啡的味道，玩家正疲憊地滑動著滑鼠。</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">角色</th><th style="text-align:left;">對話內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>玩家</strong></td><td style="text-align:left;">「（嘆氣）又是這種一成不變的生活...工作、睡覺、然後在 A 社刷掉大半的薪水...」</td></tr><tr><td style="text-align:left;"><strong>玩家</strong></td><td style="text-align:left;">「（叮一聲，螢幕跳出黑金色的視窗）嗯？這是什麼？『禁忌的 Show』邀請函？這不是普通的廣告...」</td></tr><tr><td style="text-align:left;"><strong>玩家</strong></td><td style="text-align:left;">「『尊敬的 VIP 客戶，您的消費排行已進入全球前 0.1%。我們誠邀您參與一場絕對真實、絕對禁忌的實境企劃。在這裡，慾望不需要被隱藏。』」</td></tr><tr><td style="text-align:left;"><strong>玩家</strong></td><td style="text-align:left;">「（手心微微出汗）絕對真實...絕對禁忌...也就是說，那封信裡提到的『園區』是真的存在的嗎？（眼神逐漸狂熱）如果是真的，那我這幾年砸下去的錢，總算要看到回報了。」</td></tr></tbody></table><h3 id="_0-2-規則宣告-製作人" tabindex="-1">0.2 規則宣告 (製作人) <a class="header-anchor" href="#_0-2-規則宣告-製作人" aria-label="Permalink to &quot;0.2 規則宣告 (製作人)&quot;">​</a></h3><blockquote><p><strong>場景</strong>：豪華別墅大門前。四周是茂密的森林，只有一條路通往這座燈火輝煌的建築。一名穿著考究西裝、帶著半臉面具的男子站在紅毯盡頭。</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">角色</th><th style="text-align:left;">對話內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>製作人</strong></td><td style="text-align:left;">「歡迎來到『禁忌的 Show』。我是你們的製作人，也是這裡唯一的法律。」</td></tr><tr><td style="text-align:left;"><strong>製作人</strong></td><td style="text-align:left;">「在踏入這扇門之後，請忘掉你們在現實世界中的名字、地位與道德感。在這裡，你們只有一個目標：贏得她們的『好感』。」</td></tr><tr><td style="text-align:left;"><strong>製作人</strong></td><td style="text-align:left;">「好感度就是你們的生命線。擁有它，你們就能享受天堂般的待遇；失去它，你們將會體驗到什麼叫真正的『被淘汰』。」</td></tr><tr><td style="text-align:left;"><strong>製作人</strong></td><td style="text-align:left;">「現在，請交出你們的手機。從這一刻起，你們與外界的聯繫正式切斷。祝你們...玩得愉快。」</td></tr></tbody></table><h3 id="_0-3-客廳集合-男嘉賓初見" tabindex="-1">0.3 客廳集合 (男嘉賓初見) <a class="header-anchor" href="#_0-3-客廳集合-男嘉賓初見" aria-label="Permalink to &quot;0.3 客廳集合 (男嘉賓初見)&quot;">​</a></h3><blockquote><p><strong>場景</strong>：別墅客廳。裝潢極其奢華，真皮沙發、水晶吊燈。三名風格迥異的男人已經坐定，目光不善地打量著剛進門的玩家。</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">角色</th><th style="text-align:left;">對話內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>體育男</strong></td><td style="text-align:left;">「（正在單手做伏地挺身，起身拍拍手，露出誇張的二頭肌）嘿！又來一個。你看起來弱不禁風的，該不會是靠家裡的錢買進來的吧？」</td></tr><tr><td style="text-align:left;"><strong>玩家</strong></td><td style="text-align:left;">「我是靠實力（積分）進來的。倒是你，這裡應該不是健身房吧？」</td></tr><tr><td style="text-align:left;"><strong>體育男</strong></td><td style="text-align:left;">「哈哈！有種！我就喜歡有骨氣的對手。我是體育男，記好了，等下玩遊戲的時候，我會讓你見識什麼叫真正的力量差距！」</td></tr><tr><td style="text-align:left;"><strong>暖男</strong></td><td style="text-align:left;">「（優雅地端著紅茶，微笑點頭）別理他，他腦子裡裝的都是肌肉。你好，我是暖男。雖然我們是競爭者，但我相信保持基本的禮儀對大家都好。」</td></tr><tr><td style="text-align:left;"><strong>高冷男</strong></td><td style="text-align:left;">「（獨自坐在角落，翻閱著時尚雜誌，連眼皮都沒抬一下）禮儀只是弱者的遮羞布。這裡不需要多餘的社交，反正最後能留下來的只有一個人。」</td></tr><tr><td style="text-align:left;"><strong>玩家 (內心 OS)</strong></td><td style="text-align:left;">「（環視四周）一個滿腦子肌肉的莽漢、一個笑裡藏刀的偽君子、還有一個自命不凡的怪胎...這 14 天看來會很有趣。」</td></tr></tbody></table><h3 id="_0-4-女主角依序登場-初次見面與小聊" tabindex="-1">0.4 女主角依序登場 (初次見面與小聊) <a class="header-anchor" href="#_0-4-女主角依序登場-初次見面與小聊" aria-label="Permalink to &quot;0.4 女主角依序登場 (初次見面與小聊)&quot;">​</a></h3><blockquote><p><strong>場景</strong>：客廳大門緩緩推開，沉重的木門發出吱呀聲。</p></blockquote><h4 id="_1-搖滾少女-龐克風" tabindex="-1"><strong>1. 搖滾少女 (龐克風)</strong> <a class="header-anchor" href="#_1-搖滾少女-龐克風" aria-label="Permalink to &quot;**1. 搖滾少女 (龐克風)**&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">角色</th><th style="text-align:left;">對話內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>搖滾少女</strong></td><td style="text-align:left;">「（門被粗魯地推開，重金屬音樂從她的耳機漏出）嘖，這就是所謂的豪華別墅？裝潢得像個暴發戶的客廳。」</td></tr><tr><td style="text-align:left;"><strong>搖滾少女</strong></td><td style="text-align:left;">「（嚼著口香糖，掃視全場）喂，你們這群男人，別用那種眼神看著我。我是搖滾少女，別指望我會說什麼客套話。」</td></tr><tr><td style="text-align:left;"><strong>體育男</strong></td><td style="text-align:left;">「哇喔！這風格夠辣！我喜歡有挑戰性的女人！」</td></tr><tr><td style="text-align:left;"><strong>搖滾少女</strong></td><td style="text-align:left;">「（冷冷地看著體育男）收起你的口水，大塊頭。我對四肢發達、大腦萎縮的人沒興趣。你擋到我的光了，滾開。」</td></tr><tr><td style="text-align:left;"><strong>搖滾少女</strong></td><td style="text-align:left;">「（轉向玩家）嘿，你看起來還算順眼。希望你不是那種只會躲在錢堆後面的軟蛋。」</td></tr></tbody></table><h4 id="_2-清純少女-陽光風" tabindex="-1"><strong>2. 清純少女 (陽光風)</strong> <a class="header-anchor" href="#_2-清純少女-陽光風" aria-label="Permalink to &quot;**2. 清純少女 (陽光風)**&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">角色</th><th style="text-align:left;">對話內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>清純少女</strong></td><td style="text-align:left;">「（木門輕輕推開，她有些拘謹地拉著粉色裙擺，進門先深深鞠躬）大、大家好...我是清純少女。第一次參加這種節目，真的很緊張...」</td></tr><tr><td style="text-align:left;"><strong>暖男</strong></td><td style="text-align:left;">「（立刻起身，露出最溫柔的笑容）別緊張，這裡的人都很友善。來，坐我旁邊吧，我剛泡好了熱茶。」</td></tr><tr><td style="text-align:left;"><strong>清純少女</strong></td><td style="text-align:left;">「啊，謝謝你...你人真好。這裡的裝潢好漂亮，就像夢一樣...」</td></tr><tr><td style="text-align:left;"><strong>高冷男</strong></td><td style="text-align:left;">「（冷哼）夢境通常都是用來掩蓋現實的殘酷的。」</td></tr><tr><td style="text-align:left;"><strong>清純少女</strong></td><td style="text-align:left;">「（被嚇到，縮了縮肩膀）對、對不起...我說錯什麼了嗎？」</td></tr><tr><td style="text-align:left;"><strong>玩家 (選擇肢)</strong></td><td style="text-align:left;"><em>[A. 主動幫她拿行李並安慰她]</em> / <em>[B. 遞給她一張紙巾並微笑]</em></td></tr></tbody></table><h4 id="_3-運動少女-活力風" tabindex="-1"><strong>3. 運動少女 (活力風)</strong> <a class="header-anchor" href="#_3-運動少女-活力風" aria-label="Permalink to &quot;**3. 運動少女 (活力風)**&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">角色</th><th style="text-align:left;">對話內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>運動少女</strong></td><td style="text-align:left;">「（充滿活力地推門而入，穿著緊身運動裝，完美勾勒出曲線）嗨！大家活力不錯嘛！我是運動少女。這別墅看起來真大，有游泳池嗎？」</td></tr><tr><td style="text-align:left;"><strong>體育男</strong></td><td style="text-align:left;">「當然有！等下要不要跟我去比一場？輸的人要請客喔！」</td></tr><tr><td style="text-align:left;"><strong>運動少女</strong></td><td style="text-align:left;">「好啊！我可是校隊出身的，輸了可別哭鼻子！對了，那邊那位 VIP 大哥（指玩家），你也會參加吧？」</td></tr><tr><td style="text-align:left;"><strong>運動少女</strong></td><td style="text-align:left;">「（走到玩家面前，大方地伸出手）別只是坐著發呆嘛，這是一場比賽，拿出你的鬥志來！我可不喜歡跟沒精打采的人聊天喔！」</td></tr></tbody></table><hr><h2 id="📅-day-3-劇情對話" tabindex="-1">📅 Day 3 劇情對話 <a class="header-anchor" href="#📅-day-3-劇情對話" aria-label="Permalink to &quot;📅 Day 3 劇情對話&quot;">​</a></h2><h3 id="_3-1-匿名簡訊-女主角心情獨白" tabindex="-1">3.1 匿名簡訊：女主角心情獨白 <a class="header-anchor" href="#_3-1-匿名簡訊-女主角心情獨白" aria-label="Permalink to &quot;3.1 匿名簡訊：女主角心情獨白&quot;">​</a></h3><blockquote><p><strong>類型</strong>：心情獨白 (Inner Monologue)<br><strong>觸發</strong>：玩家發送匿名簡訊後，該女主角房間的剪影演出。</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">角色</th><th style="text-align:left;">對話內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>搖滾少女</strong></td><td style="text-align:left;">「（斜眼看手機）這傢伙...眼光還不算太差嘛。既然你這麼主動，那我就稍微期待一下你之後的表現好了。」</td></tr><tr><td style="text-align:left;"><strong>清純少女</strong></td><td style="text-align:left;">「（臉紅握著手機）原來...他一直在關注我嗎？好開心...這晚我可能會興奮到睡不著呢。」</td></tr><tr><td style="text-align:left;"><strong>運動少女</strong></td><td style="text-align:left;">「（爽朗大笑）嘿，看來這場比賽越來越有趣了！有眼光！明天的小遊戲，可別讓我失望啊！」</td></tr></tbody></table><hr><h2 id="📅-day-4-劇情對話" tabindex="-1">📅 Day 4 劇情對話 <a class="header-anchor" href="#📅-day-4-劇情對話" aria-label="Permalink to &quot;📅 Day 4 劇情對話&quot;">​</a></h2><h3 id="_4-1-早上-ai-宿敵衝突對話-互動模式" tabindex="-1">4.1 早上：AI 宿敵衝突對話 (互動模式) <a class="header-anchor" href="#_4-1-早上-ai-宿敵衝突對話-互動模式" aria-label="Permalink to &quot;4.1 早上：AI 宿敵衝突對話 (互動模式)&quot;">​</a></h3><blockquote><p><strong>類型</strong>：衝突對話 (Rivalry Dialogue)<br><strong>結構</strong>：AI 挑釁 → 玩家回應 → AI 反擊</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">AI 角色</th><th style="text-align:left;">階段</th><th style="text-align:left;">對話內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>高冷男</strong></td><td style="text-align:left;"><strong>AI 挑釁</strong></td><td style="text-align:left;">「昨晚的簡訊...我看到了。別以為靠衝動就能贏得她的青睞。等下的遊戲，我會讓你明白什麼叫真正的層次感。」</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><strong>玩家回應</strong></td><td style="text-align:left;">「層次感？我只知道贏家不需要解釋。衝動有時也是實力的一種，不是嗎？」</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><strong>AI 反擊</strong></td><td style="text-align:left;">「（冷笑）呵，希望等下的遊戲中，你的實力能跟你的嘴一樣硬。我們賽場上見。」</td></tr><tr><td style="text-align:left;"><strong>體育男</strong></td><td style="text-align:left;"><strong>AI 挑釁</strong></td><td style="text-align:left;">「嘿！VIP 大哥，昨晚挺敢發的嘛！但在這園區，實力才是一切。等下不管玩什麼，我都會把你甩在後頭！」</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><strong>玩家回應</strong></td><td style="text-align:left;">「口氣不小嘛。那就看看到底是誰被甩在後頭，別到時候輸了找藉口喔。」</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><strong>AI 反擊</strong></td><td style="text-align:left;">「哈哈！好！我就喜歡這種挑釁！等下輸了可別哭鼻子，我可不會手下留情！」</td></tr><tr><td style="text-align:left;"><strong>暖男</strong></td><td style="text-align:left;"><strong>AI 挑釁</strong></td><td style="text-align:left;">「早安。昨晚你發簡訊給她了吧？其實，我也發了。因為我覺得，她值得更細緻的呵護。等下的比賽，我不會再退讓了。」</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><strong>玩家回應</strong></td><td style="text-align:left;">「細緻的呵護？聽起來像是在照顧小孩。她需要的或許是更強大的肩膀，而不是保姆。」</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><strong>AI 反擊</strong></td><td style="text-align:left;">「（眼神一閃）溫柔也是一種力量。既然你這麼有自信，那就讓我們用結果來說話吧。」</td></tr></tbody></table><h3 id="_4-2-小遊戲-女主角觀戰台詞" tabindex="-1">4.2 小遊戲：女主角觀戰台詞 <a class="header-anchor" href="#_4-2-小遊戲-女主角觀戰台詞" aria-label="Permalink to &quot;4.2 小遊戲：女主角觀戰台詞&quot;">​</a></h3><blockquote><p><strong>類型</strong>：觀戰台詞 (Spectator Lines)<br><strong>觸發</strong>：小遊戲進行中或結算畫面。</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">角色</th><th style="text-align:left;">觀戰台詞內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>搖滾少女</strong></td><td style="text-align:left;">「喂，那個 VIP，別讓我看扁了啊！拿出你的氣勢來！」</td></tr><tr><td style="text-align:left;"><strong>清純少女</strong></td><td style="text-align:left;">「雖然競爭很激烈...但我會一直看著努力的那個人...加油！」</td></tr><tr><td style="text-align:left;"><strong>運動少女</strong></td><td style="text-align:left;">「就是這樣！這才叫比賽嘛！輸掉的人可沒資格找我約會喔！」</td></tr></tbody></table><h3 id="_4-3-賽後結算-勝利與失敗對話" tabindex="-1">4.3 賽後結算：勝利與失敗對話 <a class="header-anchor" href="#_4-3-賽後結算-勝利與失敗對話" aria-label="Permalink to &quot;4.3 賽後結算：勝利與失敗對話&quot;">​</a></h3><blockquote><p><strong>類型</strong>：結果對話 (Outcome Dialogue)<br><strong>觸發</strong>：小遊戲結算後。</p></blockquote><h4 id="🏆-玩家獲勝-擊敗宿敵" tabindex="-1">🏆 玩家獲勝 (擊敗宿敵) <a class="header-anchor" href="#🏆-玩家獲勝-擊敗宿敵" aria-label="Permalink to &quot;🏆 玩家獲勝 (擊敗宿敵)&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">角色</th><th style="text-align:left;">對話內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>高冷男</strong></td><td style="text-align:left;">「（整理衣領）這次算你運氣好...下次我不會再犯同樣的低級錯誤了。」</td></tr><tr><td style="text-align:left;"><strong>體育男</strong></td><td style="text-align:left;">「可惡！竟然輸給你...這次算你厲害！但別得意太早，下次我一定贏回來！」</td></tr><tr><td style="text-align:left;"><strong>暖男</strong></td><td style="text-align:left;">「恭喜你。看來我確實低估了你的決心...不過，這場比賽才剛剛開始。」</td></tr><tr><td style="text-align:left;"><strong>玩家 (勝利宣言)</strong></td><td style="text-align:left;">「看來實力確實比口氣更有說服力。承讓了。」</td></tr><tr><td style="text-align:left;"><strong>搖滾少女 (讚美)</strong></td><td style="text-align:left;">「帥喔！剛才那個節奏感...還真有兩下子嘛。我開始對你感興趣了。」</td></tr><tr><td style="text-align:left;"><strong>清純少女 (讚美)</strong></td><td style="text-align:left;">「太好了...剛才看你那麼努力，我心跳得好快...恭喜你贏了！」</td></tr><tr><td style="text-align:left;"><strong>運動少女 (讚美)</strong></td><td style="text-align:left;">「就是這個氣勢！太精彩了！贏家就該有贏家的樣子，今晚要不要一起慶祝？」</td></tr></tbody></table><h4 id="💀-玩家失敗-輸給宿敵" tabindex="-1">💀 玩家失敗 (輸給宿敵) <a class="header-anchor" href="#💀-玩家失敗-輸給宿敵" aria-label="Permalink to &quot;💀 玩家失敗 (輸給宿敵)&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">角色</th><th style="text-align:left;">對話內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>高冷男</strong></td><td style="text-align:left;">「這就是我說的『層次』。認清現實吧，你只是個觀眾。」</td></tr><tr><td style="text-align:left;"><strong>體育男</strong></td><td style="text-align:left;">「哈哈！看到沒？這就是實力的差距！VIP 大哥，回去多練練吧！」</td></tr><tr><td style="text-align:left;"><strong>暖男</strong></td><td style="text-align:left;">「遺憾的結果。看來，我確實比你更適合站在她身邊。」</td></tr><tr><td style="text-align:left;"><strong>女主角 (失望演出)</strong></td><td style="text-align:left;">（女主角對贏家表示讚賞，轉向玩家時露出遺憾或失望的眼神，並輕輕搖頭離開。）</td></tr></tbody></table><hr><h2 id="📝-新增規範說明-contribution-guide" tabindex="-1">📝 新增規範說明 (Contribution Guide) <a class="header-anchor" href="#📝-新增規範說明-contribution-guide" aria-label="Permalink to &quot;📝 新增規範說明 (Contribution Guide)&quot;">​</a></h2><p>若要新增對話內容，請遵循以下格式：</p><ol><li><strong>標題</strong>：使用 <code>## Day X 劇情對話</code> 與 <code>### X.Y [場景描述]</code>。</li><li><strong>元數據</strong>：註明 <code>類型</code> 與 <code>觸發條件</code>。</li><li><strong>表格化</strong>：使用 Markdown 表格區分角色與內容，確保易讀性。</li><li><strong>分類標籤</strong>： <ul><li><code>心情獨白</code>：角色內心戲。</li><li><code>衝突對話</code>：男性競爭者間的對話。</li><li><code>觀戰台詞</code>：小遊戲中的互動。</li><li><code>劇情對白</code>：主線故事對話。</li></ul></li></ol>',44)])])}const h=e(d,[["render",n]]);export{f as __pageData,h as default};
